import React from "react"
import { graphql } from "gatsby"
import Layout from "../components/layout";

export default function Post({ data, location }) {
  const slug = location.pathname.replace('/', '')
  const postData = data.allMarkdownRemark.edges
    .find(({node: post}) => post.frontmatter.slug === slug)
  const { frontmatter, html } = postData.node

  return (
    <Layout>
      <div className="post">
        <header className="post__header">
          <h1>{ frontmatter.title }</h1>
          <div className="post__date">{ frontmatter.date }</div>
        </header>
        <article className="post" dangerouslySetInnerHTML={{ __html: html }}></article>
      </div>
    </Layout>
  )
}

export const query = graphql`
  query {
    allMarkdownRemark {
      edges {
        node {
          frontmatter {
            date(
              formatString: "DD MMMM YYYY"
              locale: "fr-FR"
            )
            slug
            title
          }
          html
        }
      }
    }
  }
`
